const message = $json.body.message.text.toLowerCase();
const phone = $json.body.key.remoteJid.split('@')[0];

let type = 'unknown';
let value = 0;
let category = 'outros';

// Regex simples para extrair valores
const valueMatch = message.match(/(\d+([.,]\d{1,2})?)/);
if (valueMatch) {
  value = parseFloat(valueMatch[1].replace(',', '.'));
}

if (message.includes('gastei') || message.includes('paguei') || message.includes('saída')) {
  type = 'saida';
} else if (message.includes('recebi') || message.includes('ganhei') || message.includes('entrada')) {
  type = 'entrada';
} else if (message.includes('saldo') || message.includes('quanto')) {
  type = 'consulta';
}

return {
  phone,
  message,
  type,
  value,
  category
};

const saldo = $node["Buscar Usuário"].json.saldo_mensal_atual - $node["Processar Mensagem"].json.value;
const meta = $node["Buscar Usuário"].json.meta_economia_diaria;
const gastosHoje = ($node["Buscar Usuário"].json.data_ultimo_gasto === new Date().toISOString().split('T')[0]) ? $node["Buscar Usuário"].json.gastos_diarios_acumulados + $node["Processar Mensagem"].json.value : $node["Processar Mensagem"].json.value;

let mensagem = `✅ Gasto de R$ ${$node["Processar Mensagem"].json.value.toFixed(2)} registrado!\n\n`;
mensagem += `💰 Saldo mensal atual: R$ ${saldo.toFixed(2)}\n`;
mensagem += `📉 Gastos hoje: R$ ${gastosHoje.toFixed(2)}\n`;

if (saldo < 0) {
  mensagem += `\n⚠️ Atenção: Você está no vermelho em R$ ${Math.abs(saldo).toFixed(2)}. Precisamos economizar!`;
}

return { mensagem };
